#!/usr/bin/env node
/**
 * Generate llms.txt — a distilled, machine-generated reference of SLASHED's
 * complete token/class vocabulary for the current version, sized to drop into
 * an AI coding assistant's context (Claude Code, Cursor, Windsurf, …) so it
 * uses exact `--sf-*` token and `.sf-*` class names instead of guessing.
 *
 * Source of truth is docs/api-index.json (itself generated from core/ +
 * optional/ and CI-gated), so llms.txt CANNOT drift from the live API: it is
 * regenerated by `npm run docs` and staged/verified by scripts/check-artifacts
 * (registered in scripts/artifacts.json). The cascade-layer order is read
 * straight from core/layers.css and the version from package.json — nothing
 * here is hand-maintained.
 *
 * Run:
 *   node scripts/gen-llms-txt.js
 *   npm run docs:llms
 */
import fs from 'node:fs';
import path from 'node:path';

const ROOT = path.resolve(import.meta.dirname, '..');
const OUT = path.join(ROOT, 'llms.txt');
const REPO = 'https://github.com/codeslash-dev/SLASHED';
const BLOB = `${REPO}/blob/main`;

const pkg = JSON.parse(fs.readFileSync(path.join(ROOT, 'package.json'), 'utf8'));
const api = JSON.parse(fs.readFileSync(path.join(ROOT, 'docs', 'api-index.json'), 'utf8'));

/** Canonical cascade order, read from the single `@layer …;` statement. */
function layerOrder() {
  const css = fs.readFileSync(path.join(ROOT, 'core', 'layers.css'), 'utf8');
  const m = css.match(/@layer\s+([^;]+);/);
  if (!m) return [];
  return m[1]
    .split(',')
    .map(s => s.trim().replace(/^slashed\./, ''))
    .filter(Boolean);
}

/** Preserve first-seen category order from the index (already source-ordered). */
function categoriesInOrder(entries) {
  const seen = [];
  for (const e of entries) {
    if (e.category && !seen.includes(e.category)) seen.push(e.category);
  }
  return seen;
}

/** Wrap a list of short tokens into ~100-col lines for a compact block. */
function wrapNames(names, width = 96) {
  const lines = [];
  let line = '';
  for (const n of names) {
    if (line && line.length + n.length + 1 > width) {
      lines.push(line);
      line = '';
    }
    line = line ? `${line} ${n}` : n;
  }
  if (line) lines.push(line);
  return lines.join('\n');
}

const tokens = api.entries.filter(e => e.type === 'token' && e.tier !== 'INTERNAL');
const classes = api.entries.filter(e => e.type === 'class');

const out = [];
const p = s => out.push(s);

p(`# SLASHED v${pkg.version}`);
p('');
p(
  '> SLASHED is a pure-CSS, token-driven styling framework — BEM-first, ' +
    'cascade-layered, zero runtime JS. This file is a distilled, ' +
    'machine-generated reference of SLASHED’s complete token and class ' +
    'vocabulary for this exact version, so an AI coding assistant can use real ' +
    '`--sf-*` token and `.sf-*` class names instead of guessing or ' +
    'hallucinating them.',
);
p('');
p(
  `Generated from source by \`npm run docs\` — do not edit by hand. Full prose ` +
    `guide: ${BLOB}/docs/llm-guide.md · Machine-readable index: ` +
    `${BLOB}/docs/api-index.json`,
);
p('');

// ── Conventions ──────────────────────────────────────────────────────────
p('## Conventions');
p('');
p(
  '- **Tokens** are `--sf-*` CSS custom properties: set the *knob* tokens ' +
    '(literal inputs), read the *consumption* tokens (derived via `var(--sf-…)`).',
);
p(
  '- **Classes** are `.sf-*` (structural, BEM `block__element--modifier`) and ' +
    '`.sf-is-*` (runtime states toggled by JS/ARIA). Unprefixed helpers ' +
    '(`sr-only`, `skip-link`, …) also ship.',
);
p(
  '- **Stability tiers:** PUBLIC (stable), PUBLIC-ADVANCED (stable but ' +
    'low-level / niche), INTERNAL (no guarantees, omitted here).',
);
p(
  `- **Cascade layers**, lowest→highest precedence: ` +
    layerOrder()
      .map(l => `\`${l}\``)
      .join(' → ') +
    '. Author overrides belong in `slashed.overrides` (or any unlayered rule) ' +
    'and always win.',
);
p(
  '- Prefer tokens over raw values, and BEM classes / macros over utility ' +
    'classes. Utilities and most component families ship from `optional/` ' +
    '(opt-in).',
);
p('');

// ── Tokens ───────────────────────────────────────────────────────────────
p('## Tokens');
p('');
p(
  `${tokens.length} tokens (PUBLIC + PUBLIC-ADVANCED), grouped by area. Names ` +
    `are self-descriptive; defaults, derivations and per-token notes live in ` +
    `the full guide and api-index.json.`,
);
p('');
for (const cat of categoriesInOrder(tokens)) {
  const names = tokens.filter(e => e.category === cat).map(e => e.name);
  if (!names.length) continue;
  p(`### ${cat} (${names.length})`);
  p('');
  p('```');
  p(wrapNames(names));
  p('```');
  p('');
}

// ── Classes ──────────────────────────────────────────────────────────────
p('## Classes');
p('');
p(
  `${classes.length} classes, grouped by area, each with a one-line purpose. ` +
    `\`--variant\` names are BEM modifiers of the base class above them.`,
);
p('');
for (const cat of categoriesInOrder(classes)) {
  const rows = classes.filter(e => e.category === cat);
  if (!rows.length) continue;
  p(`### ${cat} (${rows.length})`);
  p('');
  for (const c of rows) {
    const desc = (c.description || '').replace(/\s+/g, ' ').trim();
    const adv = c.tier === 'PUBLIC-ADVANCED' ? ' _(advanced)_' : '';
    p(`- \`${c.selector}\`${adv}${desc ? ` — ${desc}` : ''}`);
  }
  p('');
}

fs.writeFileSync(OUT, out.join('\n').replace(/\n+$/, '\n'));
console.log(
  `[docs:llms] → llms.txt (${tokens.length} tokens, ${classes.length} classes, v${pkg.version})`,
);
